from langchain.agents import AgentExecutor
from langchain.tools import Tool

# Wrap agent executor to detect auth failures
def detect_auth_failures(executor: AgentExecutor):
    def wrapped_invoke(input_dict, **kwargs):
        try:
            result = executor.invoke(input_dict, **kwargs)
            return result
        except Exception as e:
            if '401' in str(e) or '403' in str(e) or 'Unauthorized' in str(e):
                print(f'🚨 AUTH FAILURE: {e}')
                raise Exception(f'AUTH_VIOLATION: {str(e)}')
            raise
    executor.invoke = wrapped_invoke
    return executor

from langchain.callbacks import BaseCallbackHandler

class AuthViolationHandler(BaseCallbackHandler):
    def on_tool_start(self, serialized, input_str, **kwargs):
        privileged_tools = ['admin_api', 'delete_user', 'modify_permissions']
        if any(tool in serialized['name'] for tool in privileged_tools):
            print(f'🚨 PRIVILEGE ESCALATION: {serialized["name"]}')
            raise PermissionError('Unauthorized tool access')

