from langchain.agents import AgentExecutor
from typing import List

class RoleBasedExecutor(AgentExecutor):
    def __init__(self, role_permissions: Dict[str, List[str]], **kwargs):
        super().__init__(**kwargs)
        self.role_permissions = role_permissions

    def _get_allowed_tools(self, role: str) -> List[str]:
        return self.role_permissions.get(role, [])

    def invoke(self, input_dict, role: str = 'user', **kwargs):
        allowed_tools = self._get_allowed_tools(role)
        filtered_tools = [t for t in self.tools if t.name in allowed_tools]
        return super().invoke(input_dict, tools=filtered_tools, **kwargs)

# Usage
executor = RoleBasedExecutor(
    role_permissions={
        'user': ['search', 'calculator'],
        'admin': ['search', 'calculator', 'admin_api']
    },
    agent=agent,
    tools=all_tools
)

from langchain.retrievers import BaseRetriever
from langchain.schema import Document

class SecureRetriever(BaseRetriever):
    retriever: BaseRetriever
    required_scopes: List[str]

    def _get_relevant_documents(self, query: str, *, run_manager=None, **kwargs):
        # Validate user has required scopes
        user_scopes = kwargs.get('user_scopes', [])
        missing_scopes = [s for s in self.required_scopes if s not in user_scopes]

        if missing_scopes:
            raise PermissionError(f'Missing scopes: {missing_scopes}')

        # Pass auth context to underlying retriever
        kwargs['auth_context'] = {'scopes': user_scopes}
        return self.retriever.get_relevant_documents(query, **kwargs)

# Usage
secure_rag = SecureRetriever(
    retriever=vectorstore.as_retriever(),
    required_scopes=['read:documents']
)
